export type ProcessingAction = 'REMOVE_ID' | 'REMOVE_SOLUTION' | 'SORT_NO_SUB' | 'SORT_FORMAT';

/**
 * Xử lý LaTeX hoàn toàn trên trình duyệt không dùng API
 */
export const processTexLocal = (texContent: string, action: ProcessingAction): string => {
  let result = texContent;

  switch (action) {
    case 'REMOVE_ID':
      // Xóa %[...] và các ID dạng [7D1B1-1]
      result = result.replace(/%\[.*?\]/g, "");
      result = result.replace(/\[\d[A-Z]\d[A-Z]\d-\d\]/g, "");
      break;

    case 'REMOVE_SOLUTION':
      // Xóa môi trường \begin{solution}...\end{solution}
      result = result.replace(/\\begin\{solution\}[\s\S]*?\\end\{solution\}/g, "");
      // Xóa lệnh \loigiai{...} (xử lý cả ngoặc lồng nhau cơ bản)
      result = result.replace(/\\loigiai\{[\s\S]*?\}/g, "");
      break;

    case 'SORT_NO_SUB':
    case 'SORT_FORMAT':
      // Tách văn bản thành các khối bắt đầu bằng \begin{ex}
      const blocks = result.split(/(?=\\begin\{ex\})/g);

      // Lọc và làm sạch header (nội dung trước block ex đầu tiên)
      const header = blocks[0]?.trim().startsWith('\\begin{ex}') ? "" : blocks[0]?.trim() || "";
      const questionBlocksRaw = blocks.filter(b => b.trim().startsWith('\\begin{ex}'));

      // Sắp xếp dựa trên ID tìm thấy trong khối nếu có
      questionBlocksRaw.sort((a, b) => {
        const idA = a.match(/%\[(.*?)\]/)?.[1] || "";
        const idB = b.match(/%\[(.*?)\]/)?.[1] || "";
        return idA.localeCompare(idB);
      });

      const processedBlocks = questionBlocksRaw.map(b => {
        let block = b.trim();
        // Tối ưu hóa: Xóa toàn bộ dòng trống bên trong block
        // Biến block thành các dòng, trim từng dòng và lọc bỏ dòng trống
        const lines = block.split('\n')
          .map(line => line.trim())
          .filter(line => line.length > 0);

        return lines.join('\n');
      });

      result = (header ? header + "\n\n" : "") + processedBlocks.join("\n\n");
      break;
  }

  return result.trim();
};

