    const files = e.target.files;
    if (!files || files.length === 0) return;

    setIsProcessing(true);
    setStatus({ type: 'loading', msg: `Đang tải ${files.length} tệp...` });

    try {
      let combinedText = "";
      for (let i = 0; i < files.length; i++) {
        const text = await files[i].text();
        combinedText += (combinedText ? "\n\n% --- FILE: " + files[i].name + " ---\n" : "") + text;
      }
      setTimeout(() => {
        setRawText(combinedText);
        setIsProcessing(false);
        setStatus({ type: 'success', msg: `Đã nạp thành công ${files.length} tệp.` });
      }, 500);
    } catch (err) {
      setIsProcessing(false);
      setStatus({ type: 'error', msg: "Lỗi khi đọc tệp." });
    }
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleAction = (action: ProcessingAction, label: string) => {
    if (!rawText.trim()) {
      setStatus({ type: 'error', msg: "Vui lòng nhập dữ liệu trước!" });
      return;
    }

    setIsProcessing(true);
    setStatus({ type: 'loading', msg: `Đang ${label.toLowerCase()}...` });

    setTimeout(() => {
      try {
        const result = processTexLocal(rawText, action);
        setProcessedText(result);
        setIsProcessing(false);
        setStatus({ type: 'success', msg: `Hoàn tất: ${label}` });
