    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleAction = (action: ProcessingAction, label: string) => {
    if (!rawText.trim()) {
      setStatus({ type: 'error', msg: "Vui lòng nhập dữ liệu trước!" });
      return;
    }

    setIsProcessing(true);
    setStatus({ type: 'loading', msg: `Đang ${label.toLowerCase()}...` });

    setTimeout(() => {
      try {
        const result = processTexLocal(rawText, action);
        setProcessedText(result);
        setIsProcessing(false);
        setStatus({ type: 'success', msg: `Hoàn tất: ${label}` });
      } catch (err) {
        setIsProcessing(false);
        setStatus({ type: 'error', msg: "Lỗi xử lý LaTeX." });
      }
    }, 400);
  };

  const handleAiRewrite = async () => {
    if (!rawText.trim()) {
      setStatus({ type: 'error', msg: "Không có dữ liệu để AI xử lý!" });
      return;
    }

    setIsProcessing(true);
    setStatus({ type: 'loading', msg: "AI đang phân tích và viết lại..." });

    try {
      // Create a new instance right before making the call as per Gemini SDK guidelines
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        // Use gemini-3-pro-preview for complex reasoning tasks like LaTeX/math conversion
        model: 'gemini-3-pro-preview',
        contents: `Hãy chuyển đổi nội dung LaTeX sau đây thành văn bản thuần túy tiếng Việt, dễ đọc, giữ nguyên các công thức toán học quan trọng (sử dụng định dạng dễ nhìn hoặc Markdown), loại bỏ hoàn toàn các mã lệnh LaTeX phức tạp như \\begin, \\end, \\item, %[...]. Hãy trình bày theo danh sách các câu hỏi/bài tập rõ ràng. 
        Nội dung: 
        ${rawText.slice(0, 10000)}`,
        config: {
          systemInstruction: "Bạn là một chuyên gia toán học và giáo dục. Nhiệm vụ của bạn là chuyển đổi tài liệu LaTeX thô sang văn bản dễ đọc cho học sinh mà không làm mất đi kiến thức chuyên môn.",
          temperature: 0.1,
        }
      });

      // Use the .text property directly (not as a method)
      const text = response.text;
      if (text) {
        setProcessedText(text);
        setStatus({ type: 'success', msg: "AI đã viết lại thành công!" });
      } else {
        throw new Error("Không nhận được phản hồi từ AI");
      }
    } catch (err) {
      console.error(err);
      setStatus({ type: 'error', msg: "Lỗi kết nối AI Gemini." });
    } finally {
      setIsProcessing(false);
    }
  };

  const clearAll = () => {
    setRawText("");
    setProcessedText("");
    setStatus({ type: 'ready', msg: 'Đã xóa sạch dữ liệu' });
  };

  const copyResult = () => {
    if (!processedText) return;
    navigator.clipboard.writeText(processedText);
    setStatus({ type: 'success', msg: "Đã sao chép!" });
    setTimeout(() => setStatus({ type: 'ready', msg: 'Sẵn sàng' }), 2000);
  };

  const StatusIcon = () => {
    if (isProcessing) return <div className="w-4 h-4 border-2 border-blue-500 border-t-transparent rounded-full animate-spin"></div>;
    switch (status.type) {
      case 'success': return <svg className="w-5 h-5 text-emerald-500" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg>;
      case 'error': return <svg className="w-5 h-5 text-rose-500" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" /></svg>;
      default: return <div className="w-2.5 h-2.5 rounded-full bg-blue-500 shadow-[0_0_10px_rgba(59,130,246,0.5)]"></div>;
    }
  };

  const textSecondary = theme === 'ocean' ? 'text-slate-600' : 'text-slate-400';
  const textareaColor = theme === 'ocean' ? 'text-slate-800' : 'text-slate-200';

  return (
    <div className="h-screen flex flex-col p-4 md:p-6 w-full max-w-full overflow-hidden fade-in-section">

      <div className="fixed top-0 left-0 w-full z-50">
        <div className="progress-bar" style={{ width: isProcessing ? '70%' : '0%', opacity: isProcessing ? 1 : 0 }}></div>
      </div>

      <header className="flex flex-col sm:flex-row justify-between items-center mb-4 gap-4 px-2">
        <div className="flex items-center gap-4">
          <div className="p-2.5 bg-white/40 dark:bg-slate-800/40 rounded-xl border border-white/50 shadow-sm">
            <svg className="w-7 h-7 text-pink-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M8 7v8a2 2 0 002 2h6M8 7V5a2 2 0 012-2h4.586a1 1 0 01.707.293l4.414 4.414a1 1 0 01.293.707V15a2 2 0 01-2 2h-2M8 7H6a2 2 0 00-2 2v10a2 2 0 002 2h8a2 2 0 002-2v-2" />
            </svg>
          </div>
          <div>
            <h1 className="text-xl lg:text-2xl font-black tracking-tight flex items-center gap-2">
              <span className={theme === 'ocean' ? 'text-slate-900' : 'text-white'}>TEXREAD</span> 
              <span className="gradient-text">STUDIO</span>
            </h1>
            <p className={`text-[9px] font-bold tracking-[0.3em] uppercase opacity-70 ${textSecondary}`}>
              Smart Asset Pre-Processor & AI Translator
            </p>
          </div>
        </div>

        <div className="flex items-center gap-2">
          <button 
            onClick={() => setTheme(theme === 'ocean' ? 'midnight' : 'ocean')}
            className={`p-2.5 bg-white/30 dark:bg-white/5 hover:bg-white/50 rounded-xl border border-white shadow-sm transition-all active:scale-90 ${textSecondary}`}
          >
            {theme === 'ocean' ? (
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20.354 15.354A9 9 0 018.646 3.646 9.003 9.003 0 0012 21a9.003 9.003 0 008.354-5.646z" /></svg>
            ) : (
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 3v1m0 16v1m9-9h-1M4 9H3m15.364-6.364l-.707.707M6.343 17.657l-.707.707M16.071 16.071l.707.707M7.929 7.929l.707-.707M12 8a4 4 0 100 8 4 4 0 000-8z" /></svg>
            )}
          </button>
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="glow-button px-5 py-2.5 bg-gradient-to-r from-pink-500 to-blue-600 text-white rounded-xl text-xs font-black flex items-center gap-2 shadow-md disabled:opacity-50"
            disabled={isProcessing}
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 4v16m8-8H4" /></svg>
            TẢI .TEX
          </button>
          <input type="file" ref={fileInputRef} className="hidden" multiple accept=".tex" onChange={handleFileUpload} />
        </div>
      </header>

      <main className="flex-1 grid grid-cols-1 lg:grid-cols-2 gap-4 min-h-0 mb-4">

        <div className="flex flex-col glass-card overflow-hidden">
          <div className="flex items-center justify-between px-5 py-3 border-b border-black/5 dark:border-white/5 bg-white/10">
            <div className="flex items-center gap-3">
              <div className="w-2.5 h-2.5 rounded-full bg-pink-500 animate-pulse"></div>
              <h2 className={`text-[10px] font-black uppercase tracking-widest ${textSecondary}`}>Gốc (LaTeX)</h2>
            </div>
            <div className="flex items-center gap-4">
              <span className="text-[9px] font-black px-2.5 py-1 bg-pink-500/10 text-pink-600 rounded-full">{rawCount} CÂU</span>
              <button onClick={() => setRawText("")} className={`hover:text-pink-600 transition-colors p-1 ${textSecondary}`}>
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
              </button>
            </div>
          </div>
          <div className="flex-1 relative">
            <textarea
              className={`w-full h-full bg-transparent p-5 text-[14px] lg:text-[15px] monospace resize-none focus:outline-none custom-scrollbar placeholder:opacity-40 ${textareaColor}`}
              value={rawText}
              onChange={(e) => setRawText(e.target.value)}
              placeholder="Dán nội dung LaTeX hoặc tải tệp .tex lên..."
              disabled={isProcessing}
            />
          </div>
        </div>

        <div className="flex flex-col glass-card overflow-hidden">
          <div className="flex items-center justify-between px-5 py-3 border-b border-black/5 dark:border-white/5 bg-white/10">
            <div className="flex items-center gap-3">
              <div className="w-2.5 h-2.5 rounded-full bg-blue-500"></div>
              <h2 className={`text-[10px] font-black uppercase tracking-widest ${textSecondary}`}>Kết quả</h2>
            </div>
            <div className="flex items-center gap-4">
              <button 
                onClick={copyResult}
                className="glow-button px-3.5 py-1.5 bg-blue-600 hover:bg-blue-500 text-white rounded-lg text-[9px] font-black uppercase tracking-widest transition-all shadow-sm"
              >
                SAO CHÉP
              </button>
            </div>
          </div>
          <div className="flex-1 relative">
            <textarea
              readOnly
              className={`w-full h-full bg-transparent p-5 text-[14px] lg:text-[15px] monospace resize-none focus:outline-none custom-scrollbar ${textareaColor}`}
              value={processedText}
              placeholder="// Kết quả sau khi xử lý sẽ xuất hiện ở đây..."
            />
          </div>
        </div>
      </main>

      <footer className="glass-card p-3 flex flex-col xl:flex-row items-center justify-between gap-4 px-6 border-white/30">

        <div className="flex items-center gap-4 py-1 border-l-4 border-pink-400 pl-4 min-w-[180px]">
          <StatusIcon />
          <span className={`text-[10px] font-black uppercase tracking-widest ${status.type === 'error' ? 'text-rose-500' : textSecondary}`}>
            {status.msg}
          </span>
        </div>

        <div className="flex flex-wrap items-center justify-center gap-2">
          <TooltipButton 
            onClick={() => handleAction('REMOVE_SOLUTION', 'XÓA GIẢI')}
            className="bg-slate-700 hover:bg-slate-600 text-white"
            tooltip="Xóa sạch toàn bộ lời giải (solution/loigiai)"
            icon={<svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6" /></svg>}
            disabled={isProcessing}
          >
            XÓA GIẢI
          </TooltipButton>

          <TooltipButton 
            onClick={() => handleAction('REMOVE_ID', 'DỌN ID')}
            className="bg-slate-700 hover:bg-slate-600 text-white"
            tooltip="Loại bỏ ID định danh và mã %ID"
            icon={<svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 12H9m12 0a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>}
            disabled={isProcessing}
          >
            DỌN ID
          </TooltipButton>

          <TooltipButton 
            onClick={() => handleAction('SORT_NO_SUB', 'SẮP XẾP')}
            className="bg-indigo-600 hover:bg-indigo-500 text-white"
            tooltip="Sắp xếp câu hỏi theo thứ tự ID"
            icon={<svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M3 4h13M3 8h9m-9 4h6m4 0l4-4m0 0l4 4m-4-4v12" /></svg>}
            disabled={isProcessing}
          >
            SẮP XẾP
          </TooltipButton>

          <TooltipButton 
            onClick={() => handleAction('SORT_FORMAT', 'TỐI ƯU')}
            className="bg-emerald-600 hover:bg-emerald-500 text-white"
            tooltip="Chuẩn hóa: Không có dòng trống trong ex, 1 dòng trống giữa các ex"
            icon={<svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 6h16M4 12h16M4 18h7" /></svg>}
            disabled={isProcessing}
          >
            TỐI ƯU
          </TooltipButton>

          <TooltipButton 
            onClick={handleAiRewrite}
            className="bg-gradient-to-r from-purple-600 to-pink-600 text-white shadow-lg"
            tooltip="Dùng AI Gemini chuyển LaTeX sang văn bản dễ đọc"
            icon={<svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>}
            disabled={isProcessing}
          >
            AI VIẾT LẠI
          </TooltipButton>

          <TooltipButton 
            onClick={clearAll}
            className="bg-rose-600 hover:bg-rose-500 text-white"
            tooltip="Xóa toàn bộ nội dung cả hai cột"
            icon={<svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>}
            disabled={isProcessing}
          >
            XÓA TẤT CẢ
          </TooltipButton>
        </div>
      </footer>
    </div>
  );
};

export default App;
